#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=205;
int n,m,g[N][N],fa[N*N];
int fun(int x,int y)
{
	return (x-1)*n+y;
}
int find(int x)
{
	if(x==fa[x]) return x;
	return fa[x]=find(fa[x]);
}
struct node
{
	int cnt1,cnt2,l,r,lll[N],rr[N];//lll:最上，rr：最下 
	//1:白 2:黑 
} tr[N*4];
void pushup(int u)
{
	for(int i=1;i<=n;i++)
	{
		tr[u].lll[i]=tr[u*2].lll[i];
		tr[u].rr[i]=tr[u*2+1].rr[i];
		fa[tr[u*2].lll[i]]=tr[u*2].lll[i];
		fa[tr[u*2].rr[i]]=tr[u*2].rr[i];
		fa[tr[u*2+1].lll[i]]=tr[u*2+1].lll[i];
		fa[tr[u*2+1].rr[i]]=tr[u*2+1].rr[i];
	}
	tr[u].cnt2=tr[u*2].cnt2+tr[u*2+1].cnt2;
	tr[u].cnt1=tr[u*2].cnt1+tr[u*2+1].cnt1;
	int mid=(tr[u].l+tr[u].r)/2;
	for(int i=1;i<=n;i++)
	{
		if(g[mid][i]==g[mid+1][i])
		{
			int l=find(tr[u*2].rr[i]),r=find(tr[u*2+1].lll[i]);
			if(l!=r)
			{
				fa[l]=r;
				if((g[mid][i]==0)&&(g[mid+1][i]==0)) tr[u].cnt1--;
				if((g[mid][i]==1)&&(g[mid+1][i]==1)) tr[u].cnt2--;
			}
		}
	}
	for(int i=1;i<=n;i++)
	{
		tr[u].lll[i]=find(tr[u].lll[i]);
		tr[u].rr[i]=find(tr[u].rr[i]);
	}
}
void build(int u,int l,int r)
{
	tr[u].l=l,tr[u].r=r;
	if(l==r)
	{
		for(int i=1;i<=n;i++)
		{
			tr[u].lll[i]=tr[u].rr[i]=fa[fun(l,i)]=fun(l,i);
			if(g[l][i]==0) tr[u].cnt1++;
			else tr[u].cnt2++;
		} 
		for(int i=2;i<=n;i++)
		{
			if(g[l][i]==g[l][i-1])
			{
				tr[u].lll[i]=tr[u].rr[i]=fa[fun(l,i)]=fa[fun(l,i-1)];
				if(g[l][i]==0) tr[u].cnt1--;
				else tr[u].cnt2--;
			}
		}
		return ;
	}
	int mid=(l+r)/2;
	build(u*2,l,mid);
	build(u*2+1,mid+1,r);
	pushup(u);
	return ;
}
void update(int u,int num)
{
	if((tr[u].l>num)||(tr[u].r<num)) return ;
	if(tr[u].l==tr[u].r)
	{
		tr[u].cnt1=tr[u].cnt2=0;
		int l=tr[u].l;
		for(int i=1;i<=n;i++)
		{
			tr[u].lll[i]=tr[u].rr[i]=fa[fun(l,i)]=fun(l,i);
			if(g[l][i]==0) tr[u].cnt1++;
			else tr[u].cnt2++;
		} 
		for(int i=2;i<=n;i++)
		{
			if(g[l][i]==g[l][i-1])
			{
				tr[u].lll[i]=tr[u].rr[i]=fa[fun(l,i)]=fa[fun(l,i-1)];
				if(g[l][i]==0) tr[u].cnt1--;
				else tr[u].cnt2--;
			}
		}
		return ;
	}
	int mid=(tr[u].l+tr[u].r)/2;
	update(u*2,num);
	update(u*2+1,num);
	pushup(u);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	for(int i=1;i<=n;i++)
	{					
		for(int j=1;j<=n;j++)
		{
			cin>>g[i][j];
		}
	}
	build(1,1,n);
	cin>>m;
	while(m--)
	{
		int x,y;
		cin>>x>>y;
		g[x][y]=!g[x][y];
		update(1,x);
		cout<<tr[1].cnt2<<" "<<tr[1].cnt1<<"\n";
	}
	return 0;
}
